cd "D:\work\wordworld" && python -c "
import sys; sys.path.insert(0, 'src')
from wordworld.data.workbook import WorkbookReader
from wordworld.config.paths import WORKBOOK_PATH

sheets = WorkbookReader(WORKBOOK_PATH).read_sheets({'Attributes_属性库'})
attrs = {}
for row in sheets['Attributes_属性库']:
    if row.get('Attr_ID'):
        attrs[row['Attr_ID']] = {
            'name': row.get('Name',''),
            'initial': row.get('Initial',''),
            'min': row.get('Min',''),
            'max': row.get('Max','')
        }
print('Stamina:', attrs.get('stamina'))
print()

# Check Level_Progression for Lv99 gap
sheets2 = WorkbookReader(WORKBOOK_PATH).read_sheets({'Level_Progression_等级成长'})
for row in sheets2['Level_Progression_等级成长']:
    print(f\"Range: {row.get('Level_Range','')} | Exp_Formula: {row.get('Exp_Formula','')} | Progress_Exp: {row.get('Progress_Exp','')}\")
"
